// تأكد أن الحقل المستخدم هنا (message) هو نفسه الذي يحتوي على النص الذي تريد تنظيفه
const rawText = $json.output; 

if (!rawText || typeof rawText !== 'string') {
  return [{ json: { cleanedText: rawText || "Input was empty or not a string. Please check the input field name." } }];
}

let cleanedText = rawText;

// 1. إزالة جميع رؤوس Markdown (#, ##, ###, إلخ) في بداية السطر
cleanedText = cleanedText.replace(/^#+\s*/gm, '');

// 2. إزالة نقاط القائمة غير المرتبة (-، *، +) في بداية السطر
cleanedText = cleanedText.replace(/^[*-+]\s*/gm, '');

// 3. إزالة النجوم المزدوجة (**) والشرطات السفلية المزدوجة (__) للخط الغامق
cleanedText = cleanedText.replace(/(\*\*|__)(.*?)\1/g, '$2');

// 4. إزالة النجوم المفردة (_) أو الشرطات السفلية المفردة (_) للخط المائل
cleanedText = cleanedText.replace(/(\*|_)(.*?)\1/g, '$2');

// 5. إزالة علامات الاقتباس (>) في بداية السطر
cleanedText = cleanedText.replace(/^>\s*/gm, '');

// 6. إزالة الفواصل الناتجة عن التنظيف (مثل وجود سطرين فارغين متتاليين)
cleanedText = cleanedText.replace(/\n{2,}/g, '\n\n');

// 7. إزالة المسافات البيضاء الزائدة من البداية والنهاية
cleanedText = cleanedText.trim();


// إرجاع النص النظيف في حقل جديد
return [
  { 
    json: { 
      cleanedText: cleanedText 
    } 
  }
];
